import{_ as t,a as e}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as d,o as i,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const W=JSON.parse('{"title":"WebDAV 設定とアクセス","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/Safety/webdav-site-access.md","filePath":"ja-JP/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),o={name:"ja-JP/Safety/webdav-site-access.md"};function s(n,a,c,h,b,p){return i(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="webdav-設定とアクセス" tabindex="-1">WebDAV 設定とアクセス <a class="header-anchor" href="#webdav-設定とアクセス" aria-label="Permalink to &quot;WebDAV 設定とアクセス&quot;">​</a></h1><p>ImgBed は WebDAV を通じてファイルへアクセスできます。PC のファイルマネージャーから接続すると、対応するファイルを通常のドライブのように扱えます。</p><h2 id="使いどころ" tabindex="-1">使いどころ <a class="header-anchor" href="#使いどころ" aria-label="Permalink to &quot;使いどころ&quot;">​</a></h2><ul><li>Windows や macOS からファイルを確認したい。</li><li>WebDAV 対応クライアントでファイルを整理したい。</li><li>管理画面以外から保存済みファイルへアクセスしたい。</li></ul><h2 id="windows-11-で接続する" tabindex="-1">Windows 11 で接続する <a class="header-anchor" href="#windows-11-で接続する" aria-label="Permalink to &quot;Windows 11 で接続する&quot;">​</a></h2><ol><li>エクスプローラーを開きます。</li><li>「PC」を右クリックします。</li><li>「ネットワークの場所を追加」を選びます。</li><li>WebDAV の URL を入力します。</li><li>ユーザー名とパスワードを入力します。</li><li>接続後、通常のフォルダのように開けることを確認します。</li></ol><p><img src="'+t+'" alt="Windows 11 WebDAV 設定" loading="lazy"></p><p>接続に成功すると、エクスプローラー上で WebDAV の内容を確認できます。</p><p><img src="'+e+'" alt="Windows 表示" loading="lazy"></p><h2 id="認証情報" tabindex="-1">認証情報 <a class="header-anchor" href="#認証情報" aria-label="Permalink to &quot;認証情報&quot;">​</a></h2><p>WebDAV のユーザー名とパスワードは、ImgBed 側で設定されている認証情報を使います。公開用のアカウントではなく、必要な範囲の権限だけを持つアカウントを使うと安全です。</p><h2 id="接続できないとき" tabindex="-1">接続できないとき <a class="header-anchor" href="#接続できないとき" aria-label="Permalink to &quot;接続できないとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>確認項目</th><th>内容</th></tr></thead><tbody><tr><td>URL</td><td><code>https://</code> を含む正しい WebDAV URL か</td></tr><tr><td>認証情報</td><td>ユーザー名とパスワードが正しいか</td></tr><tr><td>権限</td><td>対象ディレクトリへの読み書きが許可されているか</td></tr><tr><td>クライアント</td><td>Windows 側で WebDAV 接続が制限されていないか</td></tr></tbody></table><p>容量確認だけが失敗し、ファイル操作はできる場合もあります。その場合は WebDAV サーバー側が容量情報を返していない可能性があります。</p>',14)])])}const f=d(o,[["render",s]]);export{W as __pageData,f as default};
